import React, { useState, useEffect } from 'react'; 
const FocusMode = () => { 
  const [time, setTime] = useState(1500); 
  return <div style={{textAlign:'center', padding:'50px'}}><h2>FOCUS MODE (POMODORO)</h2><div style={{fontSize:'48px'}}>{Math.floor(time/60)}:{(time%60).toString().padStart(2,'0')}</div></div>; 
}; export default FocusMode;
